{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoop(_cts.Token));
    }

    private async Task ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token into blocking calls so they can
                // be interrupted cooperatively instead of via Abort().
                var item = await GetNextItemAsync(token);
                await ProcessItemAsync(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Graceful shutdown requested — replaces ThreadAbortException handler.
                // Unlike Thread.Abort(), cancellation is cooperative: the token
                // was checked or thrown by a cancellation-aware API, so we know
                // exactly where we were interrupted.
                RollbackCurrentTransaction();
                break; // exit the loop cleanly (replaces ResetAbort + loop exit)
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(2);

        // Signal cancellation (replaces _running = false + Thread.Abort)
        _cts.Cancel();

        if (_workerTask is not null)
        {
            // Wait for the worker to finish, with a timeout.
            // This replaces Thread.Sleep + Thread.IsAlive polling.
            var completed = await Task.WhenAny(
                _workerTask,
                Task.Delay(timeout.Value)
            );

            if (completed != _workerTask)
            {
                // Worker didn't stop in time — log a warning.
                // In .NET 8 there is NO way to forcibly kill it.
                // You must ensure all blocking calls accept a CancellationToken.
                Console.Error.WriteLine(
                    "Warning: worker did not stop within timeout.");
            }
        }
    }

    // Synchronous overload if needed for backward compat
    public void Stop()
    {
        StopAsync().GetAwaiter().GetResult();
    }

