        // (e.g., BlockingCollection.Take), use the overload that accepts a token:
        //   return _queue.Take(token);
        //
        // If wrapping a truly non-cancellable API, run it on a thread but
        // accept that it cannot be interrupted:
        //   return await Task.Run(() => LegacyBlockingCall(), token);
        await Task.Delay(100, token);
        return new object();
    }

    private Task ProcessItemAsync(object item, CancellationToken token)
    {
        token.ThrowIfCancellationRequested();
        return Task.CompletedTask;
    }

    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

